import React, { useEffect, useState } from "react";
import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend,
  CategoryScale,
  LinearScale,
  BarElement,
} from "chart.js";
import { Doughnut, Bar } from "react-chartjs-2";
import "./Dashboard.css";

ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement);

const Dashboard = () => {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const res = await fetch("/api/dashboard-stats");
        const data = await res.json();
        setStats(data);
      } catch (err) {
        console.error("Error loading stats:", err);
      }
    };
    fetchStats();
  }, []);

  if (!stats) return <div className="loading">Loading...</div>;

  const donutOptions = {
    cutout: "70%",
    plugins: {
      legend: { display: false },
      tooltip: { enabled: false },
    },
  };

  const mainDonutData = {
    labels: ["Free", "Occupied"],
    datasets: [
      {
        data: [stats.pieChart.free, stats.pieChart.occupied],
        backgroundColor: ["#27ae60", "#e74c3c"],
        borderWidth: 0,
      },
    ],
  };

  const renderDonut = (value, color) => ({
    data: {
      datasets: [
        {
          data: [value, 100 - value],
          backgroundColor: [color, "#e0e0e0"],
          borderWidth: 0,
        },
      ],
    },
  });

  const barData = {
    labels: Object.keys(stats.barChart),
    datasets: [
      {
        label: "Free Rooms",
        data: Object.values(stats.barChart),
        backgroundColor: "#2a6bd7",
      },
    ],
  };

  return (
    <div className="dashboard-container">
      <aside className="sidebar">
        <div className="logo">CA</div>
        <nav className="nav-icons">
          <i className="fa fa-home" />
          <i className="fa fa-chart-bar" />
          <i className="fa fa-calendar" />
          <i className="fa fa-cog" />
        </nav>
      </aside>

      <div className="main-dashboard">
        <header className="topbar">
          <h2>Classroom Availability</h2>
          <div className="profile-area">
            <i className="fa fa-bell"></i>
            <img src="https://i.pravatar.cc/30" alt="User" className="avatar" />
          </div>
        </header>

        <div className="grid-dashboard">
          <div className="card donut-card large">
            <p className="chart-title">Free vs Occupied</p>
            <Doughnut data={mainDonutData} options={donutOptions} />
            <div className="donut-center">{stats.pieChart.free}</div>
          </div>

          <div className="card donut-card">
            <p className="chart-title">Projector Rooms</p>
            <Doughnut data={renderDonut(stats.resources.projectorRooms, "#f1c40f").data} options={donutOptions} />
            <div className="donut-center">{stats.resources.projectorRooms}</div>
          </div>

          <div className="card donut-card">
            <p className="chart-title">Free Labs</p>
            <Doughnut data={renderDonut(stats.resources.labs, "#f39c12").data} options={donutOptions} />
            <div className="donut-center">{stats.resources.labs}</div>
          </div>

          <div className="card donut-card">
            <p className="chart-title">Free Rooms</p>
            <Doughnut data={renderDonut(stats.resources.totalRooms - stats.pieChart.occupied, "#27ae60").data} options={donutOptions} />
            <div className="donut-center">{stats.resources.totalRooms - stats.pieChart.occupied}</div>
          </div>

          <div className="card donut-card">
            <p className="chart-title">Occupied Rooms</p>
            <Doughnut data={renderDonut(stats.pieChart.occupied, "#e74c3c").data} options={donutOptions} />
            <div className="donut-center">{stats.pieChart.occupied}</div>
          </div>

          <div className="card bar-card">
            <p className="chart-title">Free Rooms Per Day</p>
            <Bar data={barData} options={{ responsive: true, plugins: { legend: { display: false } }, scales: { y: { beginAtZero: true } } }} />
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
